import"./bootstrap";import{createApp}from"vue";import Toast from"vue-toastification";import"vue-toastification/dist/index.css";import{useToast}from"vue-toastification";import"./utils/currency-init.js";import Marketplace from"./components/Marketplace.vue";import Auctions from"./components/Auctions.vue";import SkinDetails from"./components/SkinDetails.vue";import Profile from"./components/Profile.vue";import Cart from"./components/Cart.vue";import Checkout from"./components/Checkout.vue";import CartButton from"./components/CartButton.vue";import Header from"./components/Header.vue";import FavoriteButton from"./components/FavoriteButton.vue";import Cases from"./components/Cases.vue";import CaseDetails from"./components/CaseDetails.vue";import Chat from"./components/Chat.vue";import"./footer-accordion.js";import"./loader.js";import"./custom-swiper.js";import"./script.js";const toastOptions={position:"bottom-right",timeout:8e3,closeOnClick:!0,pauseOnFocusLoss:!0,pauseOnHover:!0,draggable:!1,draggablePercent:.6,showCloseButtonOnHover:!1,hideProgressBar:!1,closeButton:"button",icon:!0,rtl:!1,maxToasts:5,newestOnTop:!0},initializeGlobalToast=()=>{const t=createApp({name:"ToastApp",setup(){const t=useToast();return window.toast=t,{}},template:"<div></div>"});t.use(Toast,toastOptions);const e=document.createElement("div");e.style.display="none",document.body.appendChild(e),t.mount(e)};document.addEventListener("DOMContentLoaded",(()=>{initializeGlobalToast();const t=document.getElementById("marketplace-app");if(t){createApp(Marketplace,{initialListings:JSON.parse(t.dataset.listings||"[]"),initialTotal:parseInt(t.dataset.total||"0"),initialHasMore:"true"===t.dataset.hasMore,initialSeller:"null"!==t.dataset.seller?JSON.parse(t.dataset.seller):null,initialSellerStats:"null"!==t.dataset.sellerStats?JSON.parse(t.dataset.sellerStats):null}).mount("#marketplace-app")}const e=document.getElementById("auctions-app");if(e){createApp(Auctions,{initialAuctions:JSON.parse(e.dataset.auctions||"[]"),initialTotal:parseInt(e.dataset.total||"0"),initialHasMore:"true"===e.dataset.hasMore,currentUser:"null"!==e.dataset.currentUser?JSON.parse(e.dataset.currentUser):null}).mount("#auctions-app")}const a=document.getElementById("cases-app");if(a){createApp(Cases,{initialCases:JSON.parse(a.dataset.cases||"[]"),user:"null"!==a.dataset.user?JSON.parse(a.dataset.user):null}).mount("#cases-app")}const o=document.getElementById("case-details-app");if(o){createApp(CaseDetails,{initialCase:JSON.parse(o.dataset.case||"{}"),caseSlug:o.dataset.caseSlug||""}).mount("#case-details-app")}const s=document.getElementById("skin-details-app");if(s){const t=parseInt(s.dataset.listingId);createApp(SkinDetails,{listingId:t}).mount("#skin-details-app")}const n=document.getElementById("profile-app");if(n){const t=createApp(Profile,{initialClient:JSON.parse(n.dataset.client||"{}"),telegramBotName:n.dataset.telegramBotName||"",depositSettings:JSON.parse(n.dataset.depositSettings||"{}")});window.telegramBotName=n.dataset.telegramBotName||"",t.mount("#profile-app")}const r=document.getElementById("cart-app");if(r){const t="null"!==r.dataset.user?JSON.parse(r.dataset.user):null,e=JSON.parse(r.dataset.routes);createApp(Cart,{user:t,routes:e}).mount("#cart-app")}if(document.getElementById("checkout-app")){createApp(Checkout).mount("#checkout-app")}if(function t(){const e=document.getElementById("header-app");if(e)try{const t="null"!==e.dataset.user?JSON.parse(e.dataset.user):null,a=JSON.parse(e.dataset.routes),o=e.dataset.logoUrl,s=parseInt(e.dataset.cartCount||"0"),n=parseInt(e.dataset.favoritesCount||"0"),r=e.dataset.extensionDownloadUrl;createApp(Header,{user:t,routes:a,logoUrl:o,initialCartCount:s,initialFavoritesCount:n,extensionDownloadUrl:r}).mount("#header-app")}catch(t){console.error("Error mounting header:",t)}else setTimeout(t,100)}(),!t){document.querySelectorAll("[data-cart-button]").forEach((t=>{const e=parseInt(t.dataset.listingId),a=t.dataset.size||"normal",o=t.dataset.variant||"primary",s="true"===t.dataset.isInCart;if(e){createApp(CartButton,{listingId:e,size:a,variant:o,initialIsInCart:s}).mount(t)}}));document.querySelectorAll("[data-favorite-button]").forEach((t=>{const e=parseInt(t.dataset.listingId);if(e){createApp(FavoriteButton,{listingId:e}).mount(t)}}))}if(document.getElementById("chat-app")){const t=createApp(Chat);t.use(Toast,toastOptions),t.mount("#chat-app")}}));